const input = $input.first().json;
const orders = input.orders || [];

if (orders.length === 0) {
  return [{
    json: {
      success: false,
      response: "I couldn't find an order matching that information. Could you please double-check your order number?",
      action: 'order_status',
      ticket_id: $('Parse Entity JSON').first().json.ticket_id,
    }
  }];
}

const order = orders[0];
const status = order.fulfillment_status || 'unfulfilled';
const financial = order.financial_status || 'unknown';
const createdAt = new Date(order.created_at).toLocaleDateString('en-US', {
  year: 'numeric', month: 'long', day: 'numeric'
});

const items = (order.line_items || [])
  .map(item => `${item.name} (x${item.quantity})`)
  .join(', ');

let trackingInfo = '';
if (order.fulfillments && order.fulfillments.length > 0) {
  const fulfillment = order.fulfillments[0];
  trackingInfo = `\nTracking: ${fulfillment.tracking_company || 'N/A'} — ${fulfillment.tracking_number || 'Not yet available'}`;
}

const statusMap = {
  'fulfilled': '✅ Shipped',
  'partial': '📦 Partially Shipped',
  'unfulfilled': '⏳ Processing',
  'null': '⏳ Processing',
};

const displayStatus = statusMap[status] || `📋 ${status}`;

const response = `Here's the status of your order #${order.order_number || order.name}:

📅 Placed: ${createdAt}
📦 Status: ${displayStatus}
💰 Total: $${order.total_price}
🛍️ Items: ${items}${trackingInfo}

Is there anything else I can help you with?`;

return [{
  json: {
    success: true,
    response: response,
    action: 'order_status',
    order_id: order.id,
    order_number: order.order_number || order.name,
    financial_status: financial,
    ticket_id: $('Parse Entity JSON').first().json.ticket_id,
  }
}];

const charges = $input.first().json.data || [];
const parsedData = $('Parse Entity JSON').first().json;
const wfData = $('When Executed by Another Workflow').first().json;
const ticketId = wfData.ticket_id ?? '';
const orderDescription = parsedData.order_id || '';
const amountMentioned = parsedData.amount_mentioned;
const productMentioned = (parsedData.product_mentioned || '').toLowerCase();

let matchedCharge = null;

for (const charge of charges) {
  const desc = (charge.description || '').toLowerCase();
  if (orderDescription && desc.includes(String(orderDescription).toLowerCase())) {
    matchedCharge = charge;
    break;
  }
}

if (!matchedCharge && productMentioned) {
  for (const charge of charges) {
    const desc = (charge.description || '').toLowerCase();
    if (desc.includes(productMentioned)) {
      matchedCharge = charge;
      break;
    }
  }
}

if (matchedCharge && matchedCharge.refunded) {
  return [{
    json: {
      success: false,
      charge_id: null,
      response: "This order has already been refunded. If you believe this is an error, let me connect you with a team member.",
      ticket_id: ticketId
    }
  }];
}

if (matchedCharge && amountMentioned) {
  const claimedAmount = Math.round(parseFloat(amountMentioned) * 100);
  const actualAmount = matchedCharge.amount;
  if (Math.abs(claimedAmount - actualAmount) > 100) {
    const actualDisplay = (actualAmount / 100).toFixed(2);
    return [{
      json: {
        success: false,
        charge_id: null,
        response: `The amount you mentioned ($${amountMentioned}) doesn't match the actual charge of $${actualDisplay} for this order. Could you please verify the amount?`,
        ticket_id: ticketId
      }
    }];
  }
}

if (!matchedCharge) {
  return [{
    json: {
      success: false,
      charge_id: null,
      response: "I couldn't find a matching payment for that order. Let me connect you with a team member who can help.",
      needs_escalation: true,
      ticket_id: ticketId
    }
  }];
}

const amountInDollars = (matchedCharge.amount / 100).toFixed(2);
return [{
  json: {
    charge_id: matchedCharge.id,
    amount: matchedCharge.amount,
    amount_display: `$${amountInDollars}`,
    description: matchedCharge.description,
    already_refunded: matchedCharge.refunded,
    auto_approve: matchedCharge.amount <= 5000,
    needs_human_approval: matchedCharge.amount > 5000,
    ticket_id: ticketId,

  }
}];

const amount = $('Match Payment to Order').first().json.amount_display;
const description = $('Match Payment to Order').first().json.description;

return [{
  json: {
    success: true,
    response: `Your refund has been processed! Here are the details:\n\n💰 Amount: ${amount}\n📋 Order: ${description || 'N/A'}\n⏱️ Processing Time: 5-7 business days to appear on your statement\n\nYou'll receive a confirmation email shortly. Is there anything else I can help with?`,
    action: 'refund',
    ticket_id: $('Match Payment to Order').first().json.ticket_id,
  }
}];

try {
  const response = $input.first().json.text || $input.first().json.output;
  const cleaned = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const entities = JSON.parse(cleaned);

  return [{
    json: {
      ...entities,
      ticket_id: $('When Executed by Another Workflow').first().json.ticket_id,
      message: $('When Executed by Another Workflow').first().json.message,
      intent: $('When Executed by Another Workflow').first().json.intent,
      sentiment: $('When Executed by Another Workflow').first().json.sentiment,
      urgency: $('When Executed by Another Workflow').first().json.urgency,
    }
  }];
} catch (e) {
  return [{
    json: {
      order_id: null,
      email: null,
      action_type: "order_status",
      product_mentioned: null,
      amount_mentioned: null,
      extraction_error: true,
      ticket_id: $('When Executed by Another Workflow').first().json.ticket_id,
      message: $('When Executed by Another Workflow').first().json.message,
      intent: $('When Executed by Another Workflow').first().json.intent,
      sentiment: $('When Executed by Another Workflow').first().json.sentiment,
      urgency: $('When Executed by Another Workflow').first().json.urgency,
    }
  }];
}

const orders = $input.first().json.orders || [];
const targetOrderId = $('Parse Entity JSON').first().json.order_id;

const matchedOrder = orders.find(order => {
  const orderName = String(order.name || '').replace('#', '');
  const orderNumber = String(order.order_number || '');
  const target = String(targetOrderId).replace('#', '').replace('VS-', '');

  return orderName === target || orderNumber === target;
});

if (!matchedOrder) {
  return [{
    json: {
      order_found: false,
      response: `I couldn't find order #${targetOrderId} in our system. Could you please double-check your order number?`,
      ticket_id: $('Parse Entity JSON').first().json.ticket_id,
    }
  }];
}

return [{
  json: {
    order_found: true,
    order_id: matchedOrder.id,
    order_number: matchedOrder.order_number || matchedOrder.name,
    total_price: matchedOrder.total_price,
    ticket_id: $('Parse Entity JSON').first().json.ticket_id,
  }
}];

